INSERT INTO docs (slug, title, content, sort_order, category) VALUES ('advanced-elite-mining', 'Untitled', '{"type":"doc","content":[{"type":"horizontalRule"},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"title: \"Elite structure Mining\" sidebar: order: 15"}]},{"type":"paragraph","content":[{"type":"text","text":"Every year, Chief Delphi lights up with the source code drops from World Champions like Team "},{"type":"text","marks":[{"type":"link","attrs":{"href":"https://github.com/Team1690","target":"_blank","rel":"noopener noreferrer nofollow","class":null,"title":null}},{"type":"bold"}],"text":"1690"},{"type":"text","text":", "},{"type":"text","marks":[{"type":"link","attrs":{"href":"https://github.com/Team254","target":"_blank","rel":"noopener noreferrer nofollow","class":null,"title":null}},{"type":"bold"}],"text":"254"},{"type":"text","text":", "},{"type":"text","marks":[{"type":"link","attrs":{"href":"https://github.com/Mechanical-Advantage","target":"_blank","rel":"noopener noreferrer nofollow","class":null,"title":null}},{"type":"bold"}],"text":"6328"},{"type":"text","text":", and "},{"type":"text","marks":[{"type":"link","attrs":{"href":"https://github.com/SwerveDriveSpecialties","target":"_blank","rel":"noopener noreferrer nofollow","class":null,"title":null}},{"type":"bold"}],"text":"2910"},{"type":"text","text":". Every year, hundreds of teams attempt to copy-paste their advanced time-of-flight models or trajectory solvers. And every year, their robots break due to architectural bloat and corrupted state variables."}]},{"type":"paragraph","content":[{"type":"text","text":"In ARESLib, we do not copy-paste. We perform structurally rigid "},{"type":"text","marks":[{"type":"bold"}],"text":"structure Mining"},{"type":"text","text":" governed by our AI Agentic Skills framework."}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"1 The Abstraction Integrity Rule"}]},{"type":"paragraph","content":[{"type":"text","text":"In 2024, Team 1690 released an incredible time-of-flight interpolation engine for shooting on the move. However, their repository was monolithic—a beautiful mess of interwoven singletons."}]},{"type":"paragraph","content":[{"type":"text","text":"When mining this logic, you must strictly strip the target repository of its structure and salvage "},{"type":"text","marks":[{"type":"italic"}],"text":"only the raw mathematics"},{"type":"text","text":". If the original code calls a motor controller directly inside the math solver, you must replace it with a decoupled "},{"type":"text","marks":[{"type":"code"}],"text":"ARESMechanismTarget"},{"type":"text","text":" payload."}]},{"type":"paragraph","content":[{"type":"text","text":":::caution "},{"type":"text","marks":[{"type":"bold"}],"text":"AI Agent Enforcement"}]},{"type":"codeBlock","attrs":{"language":null},"content":[{"type":"text","text":"ARESLib natively enforces this boundary via the `marslib-elite-mining` skill. Lead engineers can command the AI to ingest a target repository file, extract the discrete state-space models, and map them purely into our AdvantageKit `IO` layer pattern. The AI is forbidden from ingesting the hardware implementations of rival teams.\n"}]},{"type":"paragraph","content":[{"type":"text","text":":::"}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"2 Telemetry Rewiring"}]},{"type":"paragraph","content":[{"type":"text","text":"Elite teams often use complex Dashboard configurations or raw "},{"type":"text","marks":[{"type":"code"}],"text":"SmartDashboard"},{"type":"text","text":" calls. When bringing this logic into ARESLib, all telemetry calls must be gutted and replaced explicitly with AdvantageKit "},{"type":"text","marks":[{"type":"code"}],"text":"Logger.recordOutput(...)"},{"type":"text","text":" arrays, preserving determinism."}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"3 Mathematical Normalization"}]},{"type":"paragraph","content":[{"type":"text","text":"Team 254 uses custom "},{"type":"text","marks":[{"type":"code"}],"text":"Twist2d"},{"type":"text","text":" math. Team 2910 uses "},{"type":"text","marks":[{"type":"code"}],"text":"ChassisSpeeds"},{"type":"text","text":". When ingesting kinematics, you must normalize the source mathematics into ARESLib''''s expected physical units utilizing standard "},{"type":"text","marks":[{"type":"link","attrs":{"href":"https://docs.wpilib.org/en/stable/docs/software/advanced-controls/geometry/index.html","target":"_blank","rel":"noopener noreferrer nofollow","class":null,"title":null}}],"text":"ARESLib / FTClib geometry structs"},{"type":"text","text":" (e.g. "},{"type":"text","marks":[{"type":"code"}],"text":"Translation2d"},{"type":"text","text":" in Meters, not Inches; Radians, not Degrees). No raw sensor ticks are allowed past the IO layer interface."}]},{"type":"horizontalRule"},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"📖 Further Reading & External Resources"}]},{"type":"codeBlock","attrs":{"language":null},"content":[{"type":"text","text":"- [ARESLib / FTClib Official Documentation](https://docs.wpilib.org/en/stable/) - The definitive baseline resource.\n\n- [1690 Code Release (Chief Delphi)](https://www.chiefdelphi.com/t/team-1690-orbit-2024-code-release/464817) - Case study in advanced trajectory interpolation.\n"}]}]}', 70, 'Advanced');
INSERT INTO docs (slug, title, content, sort_order, category) VALUES ('advanced-simulation-best-practices', 'Untitled', '{"type":"doc","content":[{"type":"horizontalRule"},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"title: \"Simulation Best Practices\" description: \"Master ARESLib physics simulation for realistic robot development. Learn to create accurate simulations that match real-world robot behavior.\" sidebar: order: 2"}]},{"type":"paragraph","content":[{"type":"text","text":"ARESLib''''s physics simulation using Dyn4j enables you to develop and test robot code completely offline. When done correctly, simulation behavior matches real robot performance, allowing you to catch bugs before you ever touch a physical robot."}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"Simulation Philosophy"}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"🔄 Digital Twin Approach"}]},{"type":"paragraph","content":[{"type":"text","text":"ARESLib uses identical code paths for simulation and hardware."}]},{"type":"interactiveComponent","attrs":{"componentName":"Mermaid"}},{"type":"paragraph","content":[{"type":"text","text":" B{\"IO Interface\"} B B{\"IO Interface\"} B --> C[\"IOReal: Hardware\"] B C[\"IOReal: Hardware\"] B --> D[\"IOSim: Physics\"] C D[\"IOSim: Physics\"] C --> E[\"Real Robot\"] D E[\"Real Robot\"] D --> F[\"Simulation\"] E F[\"Simulation\"] E --> G[\"AdvantageKit Log\"] F G[\"AdvantageKit Log\"] F --> G"}]},{"type":"codeBlock","attrs":{"language":null},"content":[{"type":"text","text":"style A fill:#1a1a1a,stroke:#B32416,stroke-width:2px,color:#fff\nstyle B fill:#B32416,stroke:#d42e1e,stroke-width:2px,color:#fff\nstyle C fill:#2a2a2a,stroke:#1a1a1a,stroke-width:1px,color:#29b6f6\nstyle D fill:#2a2a2a,stroke:#1a1a1a,stroke-width:1px,color:#9c7bcc\nstyle E fill:#0a0a0a,stroke:#2a2a2a,stroke-width:1px,color:#666\nstyle F fill:#0a0a0a,stroke:#2a2a2a,stroke-width:1px,color:#666\nstyle G fill:#0a0a0a,stroke:#6ba3d6,stroke-width:2px,color:#6ba3d6\n"}]},{"type":"paragraph","content":[{"type":"text","text":"`} />"}]},{"type":"paragraph","content":[{"type":"text","marks":[{"type":"bold"}],"text":"Key Principle:"},{"type":"text","text":" Test real subsystems with simulated IO, not mocked hardware."}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"Physics World Setup"}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"ARESPhysicsWorld Configuration"}]},{"type":"paragraph","content":[{"type":"text","text":"The physics world manages all simulated objects and interactions."}]},{"type":"codeBlock","attrs":{"language":"java"},"content":[{"type":"text","text":"// Access the singleton physics world\nARESPhysicsWorld world = ARESPhysicsWorld.getInstance();\n\n// Configure physics parameters\nworld.setGravity(0.0, 0.0); // Top-down FTC view (no gravity in Z)\nworld.setPhysicsStepSize(0.02); // 20ms timestep = 50Hz\n"}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Game Piece Simulation"}]},{"type":"paragraph","content":[{"type":"text","text":"Spawn and manage game pieces in the physics world."}]},{"type":"codeBlock","attrs":{"language":"java"},"content":[{"type":"text","text":"// Spawn game pieces at field positions\npublic void spawnGamePieces() {\n    ARESPhysicsWorld world = ARESPhysicsWorld.getInstance();\n    \n    // Spawn fuel balls at specific positions\n    world.spawnGamePiece(2.0, 3.0);  // x, y in meters\n    world.spawnGamePiece(2.5, 3.0);\n    world.spawnGamePiece(3.0, 3.0);\n    \n    // Game pieces automatically interact with robot bumper\n}\n"}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Collision Detection"}]},{"type":"paragraph","content":[{"type":"text","text":"Configure realistic collision behavior."}]},{"type":"codeBlock","attrs":{"language":"java"},"content":[{"type":"text","text":"public class SimulationConfig {\n    public void setupCollisions() {\n        ARESPhysicsWorld world = ARESPhysicsWorld.getInstance();\n        \n        // Configure robot bumper dimensions\n        double bumperLength = 0.8; // meters\n        double bumperWidth = 0.8;  // meters\n        \n        // Robot body will collide with:\n        // - Game pieces\n        // - Field walls\n        // - Other robots (in multi-robot simulation)\n    }\n}\n"}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"IO Simulation Patterns"}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Swerve Module Simulation"}]},{"type":"paragraph","content":[{"type":"text","text":"Accurate swerve module simulation is critical for realistic behavior."}]},{"type":"codeBlock","attrs":{"language":"java"},"content":[{"type":"text","text":"public class SwerveModuleIOSim implements SwerveModuleIO {\n    private double drivePosition = 0.0;\n    private double driveVelocity = 0.0;\n    private double turnPosition = 0.0;\n    private double turnVelocity = 0.0;\n    \n    private final SwerveModuleSimulation moduleSim;\n    \n    public SwerveModuleIOSim(int moduleIndex) {\n        // Get simulation from physics world\n        moduleSim = ARESPhysicsWorld.getInstance()\n            .getSwerveDriveSimulation()\n            .getModules()[moduleIndex];\n    }\n    \n    @Override\n    public void updateInputs(SwerveModuleIOInputs inputs) {\n        // Update from physics simulation\n        inputs.drivePositionRad = drivePosition;\n        inputs.driveVelocityRadPerSec = driveVelocity;\n        inputs.turnPositionRad = turnPosition;\n        inputs.turnVelocityRadPerSec = turnVelocity;\n        \n        // Simulate sensor latency\n        inputs.driveVelocityRadPerSec += (Math.random() - 0.5) * 0.01;\n    }\n    \n    @Override\n    public void setDriveVoltage(double volts) {\n        // Simple physics model\n        double acceleration = volts / 10.0; // Simplified motor response\n        driveVelocity += acceleration * 0.02; // 20ms timestep\n        drivePosition += driveVelocity * 0.02;\n        \n        // Apply to physics simulation\n        moduleSim.setState(driveVelocity, turnPosition);\n    }\n    \n    @Override\n    public void setTurnVoltage(double volts) {\n        double acceleration = volts / 5.0; // Turn motor responds faster\n        turnVelocity += acceleration * 0.02;\n        turnPosition += turnVelocity * 0.02;\n        \n        // Apply to physics simulation\n        moduleSim.setState(driveVelocity, turnPosition);\n    }\n}\n"}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Gyro Simulation"}]},{"type":"paragraph","content":[{"type":"text","text":"Accurate gyro simulation for realistic heading feedback."}]},{"type":"codeBlock","attrs":{"language":"java"},"content":[{"type":"text","text":"public class GyroIOSim implements GyroIO {\n    private double yaw = 0.0;\n    private double pitch = 0.0;\n    private double roll = 0.0;\n    \n    private final SwerveDriveSimulation driveSim;\n\n    public GyroIOSim() {\n        this.driveSim = ARESPhysicsWorld.getInstance().getSwerveDriveSimulation();\n    }\n\n    @Override\n    public void updateInputs(GyroIOInputs inputs) {\n        // Get heading from physics simulation\n        var simPose = driveSim.getPose();\n        yaw = simPose.getRotation().getRadians();\n        \n        // Add small noise to simulate real gyro\n        yaw += (Math.random() - 0.5) * 0.001;\n        \n        inputs.connected = true;\n        inputs.yawPositionRad = yaw;\n        inputs.yawVelocityRadPerSec = driveSim.getChassisSpeeds().omegaRadiansPerSecond;\n    }\n}\n"}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Vision Simulation"}]},{"type":"paragraph","content":[{"type":"text","text":"Simulate AprilTag detection with realistic accuracy."}]},{"type":"codeBlock","attrs":{"language":"java"},"content":[{"type":"text","text":"public class AprilTagVisionIOSim implements VisionIO {\n    private final SwerveDriveSimulation driveSim;\n    private final AprilTagFieldLayout tagLayout;\n    \n    public AprilTagVisionIOSim() {\n        this.driveSim = ARESPhysicsWorld.getInstance().getSwerveDriveSimulation();\n        this.tagLayout = AprilTagFieldLayout.loadField(AprilTagField.k2024Crescendo);\n    }\n\n    @Override\n    public void updateInputs(VisionIOInputs inputs) {\n        Pose2d robotPose = driveSim.getPose();\n        \n        // Find visible tags\n        List<div data-component=\"AprilTag\"></div> visibleTags = new ArrayList<>();\n        for (AprilTag tag : tagLayout.getTags()) {\n            double distance = robotPose.getTranslation().getDistance(tag.pose.getTranslation());\n            \n            // Tags visible within 5 meters\n            if (distance < 5.0) {\n                // Add detection noise\n                double noise = distance * 0.05; // 5cm noise per meter\n                Pose2d noisyPose = addNoise(tag.pose, noise);\n                visibleTags.add(new AprilTag(tag.ID, noisyPose, distance));\n            }\n        }\n        \n        inputs.timestamps = new double[visibleTags.size()];\n        inputs.frames = new double[visibleTags.size()];\n        inputs.tagIds = new int[visibleTags.size()];\n        poses = new Pose3d[visibleTags.size()];\n        \n        for (int i = 0; i < visibleTags.size(); i++) {\n            AprilTag tag = visibleTags.get(i);\n            inputs.tagIds[i] = tag.id;\n            poses[i] = new Pose3d(tag.pose);\n            inputs.timestamps[i] = Timer.getFPGATimestamp();\n        }\n    }\n    \n    private Pose2d addNoise(Pose3d pose, double amount) {\n        // Add Gaussian noise to position\n        double noisyX = pose.getX() + (Math.random() - 0.5) * amount;\n        double noisyY = pose.getY() + (Math.random() - 0.5) * amount;\n        return new Pose2d(noisyX, noisyY, pose.getRotation().toRotation2d());\n    }\n}\n"}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"Test Simulation Patterns"}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Realistic Simulation Loop"}]},{"type":"paragraph","content":[{"type":"text","text":"Proper simulation timing and order is critical."}]},{"type":"codeBlock","attrs":{"language":"java"},"content":[{"type":"text","text":"@Test\npublic void testAutonomousWithSimulation() {\n    ARESTestHarness.reset();\n    \n    // Create subsystems with simulated IO\n    SwerveDrive drive = new SwerveDrive(modules, gyroIO, powerManager, config);\n    ARESVision vision = new ARESVision(visionIO, visionConfig);\n    \n    // Spawn game pieces\n    ARESPhysicsWorld world = ARESPhysicsWorld.getInstance();\n    world.spawnGamePiece(5.0, 3.0);\n    world.spawnGamePiece(6.0, 4.0);\n    \n    // Schedule autonomous command\n    Command autoCommand = getPathPlannerAuto(\"TestAuto\");\n    autoCommand.schedule();\n    \n    // Run simulation loop\n    for (int i = 0; i < 500; i++) { // 10 seconds @ 50Hz\n        // 1. Update Driver Station (prevents robot disable)\n        DriverStationSim.notifyNewData();\n        \n        // 2. Advance time\n        SimHooks.stepTiming(0.02); // 20ms\n        \n        // 3. Process commands and subsystems\n        CommandScheduler.getInstance().run();\n        \n        // 4. Update physics world\n        world.update(0.02);\n        \n        // 5. Check for completion\n        if (!autoCommand.isScheduled()) {\n            break;\n        }\n    }\n    \n    // Verify autonomous completed successfully\n    assertTrue(autoCommand.isFinished());\n    assertEquals(2, getIntakeGamePieceCount()); // Should have intaked 2 pieces\n}\n"}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Physics-Accurate Testing"}]},{"type":"paragraph","content":[{"type":"text","text":"Test realistic physical interactions."}]},{"type":"codeBlock","attrs":{"language":"java"},"content":[{"type":"text","text":"@Test\npublic void testGamePieceIntake() {\n    ARESTestHarness.reset();\n    \n    // Create intake with simulated IO\n    IntakeSubsystem intake = new IntakeSubsystem(new IntakeIOSim(), config);\n    \n    // Spawn game piece in front of robot\n    ARESPhysicsWorld world = ARESPhysicsWorld.getInstance();\n    world.spawnGamePiece(1.0, 0.0); // 1 meter in front\n    \n    // Start intake\n    intake.intake();\n    \n    // Run simulation until intake completes\n    for (int i = 0; i < 100; i++) {\n        DriverStationSim.notifyNewData();\n        SimHooks.stepTiming(0.02);\n        CommandScheduler.getInstance().run();\n        world.update(0.02);\n        \n        if (intake.hasGamePiece()) {\n            break;\n        }\n    }\n    \n    // Verify intake succeeded\n    assertTrue(intake.hasGamePiece(), \"Should have intaked game piece\");\n    \n    // Verify game piece moved with robot\n    Pose2d robotPose = drive.getPose();\n    // Game piece should be at robot position\n}\n"}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Error Simulation"}]},{"type":"paragraph","content":[{"type":"text","text":"Test error handling with simulated failures."}]},{"type":"codeBlock","attrs":{"language":"java"},"content":[{"type":"text","text":"@Test\npublic void testVisionFailureRecovery() {\n    ARESTestHarness.reset();\n    \n    // Create vision with simulated failure\n    FailingVisionIOSim visionIO = new FailingVisionIOSim();\n    ARESVision vision = new ARESVision(visionIO, config);\n    \n    // Simulate vision failure\n    visionIO.setFail(true);\n    \n    // Run for 1 second with failed vision\n    for (int i = 0; i < 50; i++) {\n        DriverStationSim.notifyNewData();\n        SimHooks.stepTiming(0.02);\n        CommandScheduler.getInstance().run();\n    }\n    \n    // Verify fault was reported\n    assertTrue(ARESFaultManager.hasFault(\"Vision unavailable\"));\n    \n    // Simulate vision recovery\n    visionIO.setFail(false);\n    \n    // Run for 1 second with recovered vision\n    for (int i = 0; i < 50; i++) {\n        DriverStationSim.notifyNewData();\n        SimHooks.stepTiming(0.02);\n        CommandScheduler.getInstance().run();\n    }\n    \n    // Verify fault cleared\n    assertFalse(ARESFaultManager.hasFault(\"Vision unavailable\"));\n}\n"}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"Simulation Accuracy Validation"}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Compare Simulation vs Reality"}]},{"type":"paragraph","content":[{"type":"text","text":"Validate that simulation matches real robot behavior."}]},{"type":"codeBlock","attrs":{"language":"java"},"content":[{"type":"text","text":"public class SimulationValidation {\n    public static void main(String[] args) {\n        // 1. Run same autonomous in simulation\n        Pose2d simFinalPose = runInSimulation();\n        \n        // 2. Run same autonomous on real robot\n        Pose2d realFinalPose = runOnRealRobot();\n        \n        // 3. Compare results\n        double positionError = simFinalPose.getTranslation()\n            .getDistance(realFinalPose.getTranslation());\n        double rotationError = Math.abs(simFinalPose.getRotation()\n            .minus(realFinalPose.getRotation()).getRadians());\n        \n        System.out.println(\"Position error: \" + positionError + \" meters\");\n        System.out.println(\"Rotation error: \" + Math.toDegrees(rotationError) + \" degrees\");\n        \n        // 4. If error is large, tune simulation parameters\n        if (positionError > 0.1 || rotationError > Math.toRadians(5)) {\n            System.out.println(\"WARNING: Simulation accuracy needs tuning!\");\n            tuneSimulationParameters();\n        }\n    }\n}\n"}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Parameter Tuning"}]},{"type":"paragraph","content":[{"type":"text","text":"Adjust simulation parameters to match real robot."}]},{"type":"codeBlock","attrs":{"language":"java"},"content":[{"type":"text","text":"public class SimulationTuner {\n    public void tuneSwerveSimulation() {\n        SwerveConfig config = SwerveConfig.fromFile(\"config.json\");\n        \n        // 1. Measure real robot max velocity\n        double realMaxVelocity = measureRealMaxVelocity();\n        \n        // 2. Measure simulated max velocity\n        double simMaxVelocity = measureSimulatedMaxVelocity();\n        \n        // 3. Adjust config to match\n        double ratio = realMaxVelocity / simMaxVelocity;\n        config.setMaxLinearSpeedMps(config.maxLinearSpeedMps() * ratio);\n        \n        // 4. Repeat for angular velocity\n        double realMaxOmega = measureRealMaxOmega();\n        double simMaxOmega = measureSimulatedMaxOmega();\n        double omegaRatio = realMaxOmega / simMaxOmega;\n        config.setMaxAngularSpeedRadPerSec(\n            config.maxAngularSpeedRadPerSec() * omegaRatio\n        );\n    }\n}\n"}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"Advanced Simulation Techniques"}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Multi-Robot Simulation"}]},{"type":"paragraph","content":[{"type":"text","text":"Simulate interaction with other robots."}]},{"type":"codeBlock","attrs":{"language":"java"},"content":[{"type":"text","text":"public class MultiRobotSimulation {\n    public void simulateDefense() {\n        ARESPhysicsWorld world = ARESPhysicsWorld.getInstance();\n        \n        // Add defender robot\n        SwerveDriveSimulation defender = world.addSwerveDrive(\n            new Pose2d(4.0, 2.0, new Rotation2d()),\n        );\n        \n        // Program defender behavior\n        Command defenderCommand = new DefendCommand(defender, 3.0, 2.0);\n        defenderCommand.schedule();\n        \n        // Run interaction simulation\n        for (int i = 0; i < 500; i++) {\n            DriverStationSim.notifyNewData();\n            SimHooks.stepTiming(0.02);\n            CommandScheduler.getInstance().run();\n            world.update(0.02);\n        }\n    }\n}\n"}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Field Obstacles"}]},{"type":"paragraph","content":[{"type":"text","text":"Add realistic field elements to simulation."}]},{"type":"codeBlock","attrs":{"language":"java"},"content":[{"type":"text","text":"public class FieldObstacles {\n    public void addREBUILTObstacles() {\n        ARESPhysicsWorld world = ARESPhysicsWorld.getInstance();\n        \n        // Add REBUILT obstacles (2024 game)\n        world.addObstacle(2.0, 3.0, 0.5, 0.5); // x, y, width, height\n        world.addObstacle(6.0, 3.0, 0.5, 0.5);\n        world.addObstacle(4.0, 1.0, 1.0, 0.3);\n        \n        // Robot will collide with these obstacles\n    }\n}\n"}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Environment Simulation"}]},{"type":"paragraph","content":[{"type":"text","text":"Simulate real-world conditions."}]},{"type":"codeBlock","attrs":{"language":"java"},"content":[{"type":"text","text":"public class EnvironmentSimulation {\n    public void simulateFieldConditions() {\n        // Simulate friction variations\n        double[][] frictionMap = {\n            {0.8, 0.8, 0.7, 0.8, 0.8}, // Different friction across field\n            {0.8, 0.7, 0.6, 0.7, 0.8},\n            {0.8, 0.7, 0.6, 0.7, 0.8},\n            {0.8, 0.8, 0.7, 0.8, 0.8},\n            {0.8, 0.8, 0.8, 0.8, 0.8}\n        };\n        \n        // Apply friction based on robot position\n        Pose2d robotPose = drive.getPose();\n        int x = (int) robotPose.getX();\n        int y = (int) robotPose.getY();\n        double friction = frictionMap[y][x];\n        \n        // Adjust wheel COF based on field location\n        config.setWheelCOFStatic(friction);\n    }\n}\n"}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"Common Simulation Pitfalls"}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"❌ Don''''t Mock Physics"}]},{"type":"codeBlock","attrs":{"language":"java"},"content":[{"type":"text","text":"// BAD: Doesn''''t test real physics\n@Test\npublic void testWithMock() {\n    when(drive.getPose()).thenReturn(new Pose2d(1.0, 2.0, new Rotation2d()));\n    // Test passes but doesn''''t validate physics\n}\n"}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"✅ Do Use Real Physics"}]},{"type":"codeBlock","attrs":{"language":"java"},"content":[{"type":"text","text":"// GOOD: Tests real physics behavior\n@Test\npublic void testWithPhysics() {\n    ARESTestHarness.reset();\n    SwerveDrive drive = new SwerveDrive(new SwerveModuleIOSim(), ...);\n    \n    for (int i = 0; i < 100; i++) {\n        drive.runVelocity(new ChassisSpeeds(1.0, 0.0, 0.0));\n        ARESPhysicsWorld.getInstance().update(0.02);\n    }\n    \n    // Validate actual physics result\n    assertTrue(drive.getPose().getX() > 0.5); // Robot moved forward\n}\n"}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"Simulation Verification Checklist"}]},{"type":"paragraph","content":[{"type":"text","text":"Before trusting simulation results:"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Physics timestep matches real robot timing (20ms)"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"All subsystems use simulated IO."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Simulation loop updates DriverStation."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Physics world updated each iteration."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Simulation parameters tuned to real robot."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Vision simulation includes realistic noise."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Game pieces interact with robot bumper."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Field boundaries enforced."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Multi-robot interactions work correctly."}]}]}]},{"type":"horizontalRule"},{"type":"paragraph","content":[{"type":"text","marks":[{"type":"bold"}],"text":"Ready to simulate?"},{"type":"text","text":" Run "},{"type":"text","marks":[{"type":"code"}],"text":"./gradlew simulateJava"},{"type":"text","text":" to start the simulation GUI and see your robot code in action!"}]}]}', 80, 'Advanced');
INSERT INTO docs (slug, title, content, sort_order, category) VALUES ('culture-core-values', 'Untitled', '{"type":"doc","content":[{"type":"horizontalRule"},{"type":"paragraph","content":[{"type":"text","text":"title: \"FIRST® Core Values\" description: \"Discover the cultural foundation of ARESLib: Discovery, Innovation, Impact, Teamwork, Inclusion, and Fun.\" id: \"core-values\" template: \"doc\" sidebar: order: 0 label: \"Core Values\" head:"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"tag: style content: \"h1#\\_top { display: none !important; }\""}]}]}]},{"type":"horizontalRule"},{"type":"heading","attrs":{"level":1},"content":[{"type":"text","marks":[{"type":"italic"}],"text":"FIRST"},{"type":"text","text":"® Core Values"}]},{"type":"paragraph","content":[{"type":"text","text":"At ARES 23247, we don''''t just build robots—we build people. The "},{"type":"text","marks":[{"type":"bold"},{"type":"italic"}],"text":"FIRST"},{"type":"text","marks":[{"type":"bold"}],"text":"® Core Values"},{"type":"text","text":" are the foundation of everything we do. In ARESLib, these values aren''''t just posters on the wall; they are the architectural principles that govern our code, our collaboration, and our impact on the FTC community."}]},{"type":"interactiveComponent","attrs":{"componentName":"HomeCoreValues"}},{"type":"horizontalRule"},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"0 Why Culture Matters in Code"}]},{"type":"paragraph","content":[{"type":"text","text":"Elite robotics software is more than just math and logic. It is a reflection of the team''''s ability to "},{"type":"text","marks":[{"type":"bold"}],"text":"Teamwork"},{"type":"text","text":" through complex problems and "},{"type":"text","marks":[{"type":"bold"}],"text":"Discovery"},{"type":"text","text":" the limits of what is possible. ARESLib was designed to be a platform where:"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","marks":[{"type":"bold"}],"text":"Innovation"},{"type":"text","text":" is encouraged by making simulation accessible to every student."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","marks":[{"type":"bold"}],"text":"Inclusion"},{"type":"text","text":" is enforced by building world-class accessibility into our documentation."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","marks":[{"type":"bold"}],"text":"Impact"},{"type":"text","text":" is measured by how much we help other teams grow through our open-source contributions."}]}]}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"Our Philosophy"}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Discovery & Innovation"}]},{"type":"paragraph","content":[{"type":"text","text":"We explore new skills and ideas with creative persistence. ARESLib''''s "},{"type":"text","marks":[{"type":"bold"}],"text":"zero-allocation"},{"type":"text","text":" and "},{"type":"text","marks":[{"type":"bold"}],"text":"250Hz odometry"},{"type":"text","text":" are the results of relentless innovation—pushing beyond standard solutions to find what works best in a championship environment."}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Teamwork & Inclusion"}]},{"type":"paragraph","content":[{"type":"text","text":"We are stronger when we work together and respect our differences. Our framework is designed for a multi-student workflow, with structured IO layers that allow mechanical and software students to collaborate through high-fidelity physics simulation. In honor of our founding mentor Phil Tucker and the Tucker Teams initiative, we live by the motto: "},{"type":"text","marks":[{"type":"bold"}],"text":"\"No robot left behind.\""}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Impact & Fun"}]},{"type":"paragraph","content":[{"type":"text","text":"We use what we learn to improve our world and celebrate our successes! Every "},{"type":"text","marks":[{"type":"code"}],"text":"BUILD SUCCESSFUL"},{"type":"text","text":" is a moment for "},{"type":"text","marks":[{"type":"bold"}],"text":"Fun"},{"type":"text","text":". We share our work so that the entire FTC community can benefit from our discovery. As the 2017 FIRST Championship Chairman''''s (Impact) Award winners, we ensure our code structure embodies \"The ARES Plan\"—acting as a catalyst to Engage, Inspire, and Sustain the next generation of innovators."}]},{"type":"horizontalRule"},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"ARESLib Specific Values"}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"The Appalachian Mindset"}]},{"type":"paragraph","content":[{"type":"text","text":"FTC engineering is inherently difficult. We actively encourage students to cultivate grit and determination when learning hard things. Transitioning to zero-allocation loops, advanced odometry, and high-fidelity physics requires immense persistence. The Appalachian Mindset means pushing through the initial learning curve, pursuing non-stop innovation, and choosing the complete, mathematically robust path even when it is challenging."}]},{"type":"horizontalRule"},{"type":"blockquote","content":[{"type":"paragraph","content":[{"type":"text","text":"\"The robots are the vehicle; the students are the cargo.\" — "},{"type":"text","marks":[{"type":"bold"}],"text":"Team ARES 23247"}]}]}]}', 30, 'Culture & Contributing');
INSERT INTO docs (slug, title, content, sort_order, category) VALUES ('culture-appalachian-mindset', 'The Appalachian Mindset', '{"type":"doc","content":[{"type":"paragraph","content":[{"type":"text","text":"At "},{"type":"text","marks":[{"type":"bold"}],"text":"ARES 23247"},{"type":"text","text":", we recognize that creating world-class robots doesn''''t happen by taking the easy way out. That is why "},{"type":"text","marks":[{"type":"bold"}],"text":"The Appalachian Mindset"},{"type":"text","text":" is a foundational pillar of our team''''s ethos and the ARESLib framework. It is defined by three core traits: "},{"type":"text","marks":[{"type":"bold"}],"text":"Grit"},{"type":"text","text":", "},{"type":"text","marks":[{"type":"bold"}],"text":"Determination"},{"type":"text","text":", and "},{"type":"text","marks":[{"type":"bold"}],"text":"Innovation"},{"type":"text","text":"."}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"Grit in the Face of Complexity"}]},{"type":"paragraph","content":[{"type":"text","text":"FTC software engineering is inherently difficult. You will face concepts that feel insurmountable:"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Transitioning from simple "},{"type":"text","marks":[{"type":"code"}],"text":"TimedRobot"},{"type":"text","text":" architectures to advanced "},{"type":"text","marks":[{"type":"bold"}],"text":"State Machines"},{"type":"text","text":"."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Trusting "},{"type":"text","marks":[{"type":"bold"}],"text":"Zero-Mocking"},{"type":"text","text":" simulations to validate logic before the robot is built."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Adopting "},{"type":"text","marks":[{"type":"bold"}],"text":"Zero-Allocation"},{"type":"text","text":" logic rather than continually relying on the garbage collector."}]}]}]},{"type":"paragraph","content":[{"type":"text","text":"It takes immense grit to learn that the \"easy way\" will ultimately bottleneck the robot in competition. The Appalachian Mindset means pushing through the initial learning curve and choosing the mathematically robust path—even when it requires hours of reading documentation and tuning SysId feedforwards."}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"Determination to Fail Forward"}]},{"type":"paragraph","content":[{"type":"text","text":"We encourage students to actively engage with failure as a tool for progress:"}]},{"type":"orderedList","attrs":{"start":1,"type":null},"content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","marks":[{"type":"bold"}],"text":"Take on Hard Tickets:"},{"type":"text","text":" Volunteer for the subsystem you don''''t instantly understand. Have the determination to figure it out."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","marks":[{"type":"bold"}],"text":"Fail Forward:"},{"type":"text","text":" When a simulation test crashes or the robot behaves erratically, do not retreat to old code. Analyze the AdvantageKit log, diagnose the root cause, and formulate a solution."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","marks":[{"type":"bold"}],"text":"Persist Through Bugs:"},{"type":"text","text":" Finding the elusive NaN error deep in the Swerve kinematics takes determination. We don''''t give up; we dig deeper."}]}]}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"Continuous Innovation"}]},{"type":"paragraph","content":[{"type":"text","text":"Grit and determination ultimately fuel "},{"type":"text","marks":[{"type":"bold"}],"text":"Innovation"},{"type":"text","text":". By refusing to settle for standard solutions and constantly pushing the boundaries of what our software can do, we develop groundbreaking architectures like 250Hz Odometry threads and flawless hardware abstractions."}]},{"type":"paragraph","content":[{"type":"text","text":"By adopting the Appalachian Mindset, we ensure that our students emerge from ARES not just as capable developers, but as resilient, innovative engineers ready to tackle the hardest problems the world has to offer."}]}]}', 20, 'Culture & Contributing');
INSERT INTO docs (slug, title, content, sort_order, category) VALUES ('interactive-code-challenges', 'Untitled', '{"type":"doc","content":[{"type":"horizontalRule"},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"title: \"Interactive Code Challenges\" description: \"Practice your robot programming skills with these hands-on coding exercises.\" sidebar: order: 2"}]},{"type":"paragraph","content":[{"type":"text","text":"Practice your robot programming skills! These challenges start simple and get progressively harder."}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"How to Use These Challenges"}]},{"type":"orderedList","attrs":{"start":1,"type":null},"content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","marks":[{"type":"bold"}],"text":"Read the problem"},{"type":"text","text":" carefully."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","marks":[{"type":"bold"}],"text":"Think about the solution"},{"type":"text","text":" before coding."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","marks":[{"type":"bold"}],"text":"Write the code"},{"type":"text","text":" in your robot project."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","marks":[{"type":"bold"}],"text":"Test in simulation"},{"type":"text","text":" to verify it works."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","marks":[{"type":"bold"}],"text":"Reveal the solution"},{"type":"text","text":" to compare your approach."}]}]}]},{"type":"horizontalRule"},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"Challenge 1: Drive in a Square"}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"🎯 Goal"}]},{"type":"paragraph","content":[{"type":"text","text":"Make the robot drive in a 2m × 2m square and return to the starting position."}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"📋 Requirements"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Drive forward 2 meters."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Turn 90 degrees right."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Drive forward 2 meters."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Turn 90 degrees right."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Repeat until robot completes square."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Should work in simulation."}]}]}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"💡 Hints"}]},{"type":"paragraph","content":[{"type":"text","text":"Hint 1: Think about the sequence"}]},{"type":"paragraph","content":[{"type":"text","text":"You need to repeat these actions:"}]},{"type":"orderedList","attrs":{"start":1,"type":null},"content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Drive forward 2m."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Turn 90°"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Do this 4 times total."}]}]}]},{"type":"paragraph","content":[{"type":"text","text":"Hint 2: Use Commands.sequence()"}]},{"type":"paragraph","content":[{"type":"text","marks":[{"type":"code"}],"text":"Commands.sequence()"},{"type":"text","text":" runs commands one after another. Each action can be its own command."}]},{"type":"codeBlock","attrs":{"language":"java"},"content":[{"type":"text","text":"Commands.sequence(\n    command1,\n    command2,\n    command3\n);\n"}]},{"type":"paragraph","content":[{"type":"text","text":"Hint 3: Create a DriveDistance command"}]},{"type":"paragraph","content":[{"type":"text","text":"You''''ll need a command that drives a specific distance. Use odometry to know when to stop."}]},{"type":"codeBlock","attrs":{"language":"java"},"content":[{"type":"text","text":"public boolean isFinished() {\n    double distance = startingPose.getTranslation().getDistance(\n        drivetrain.getPose().getTranslation()\n    );\n    return distance >= targetDistance;\n}\n"}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"✅ Solution"}]},{"type":"paragraph","content":[{"type":"text","text":"👁️ Reveal Solution"}]},{"type":"codeBlock","attrs":{"language":"java"},"content":[{"type":"text","text":"// Command to drive specific distance\npublic class DriveDistance extends Command {\n    private final Drivetrain drivetrain;\n    private final double distance;\n    private Pose2d startingPose;\n    \n    public DriveDistance(Drivetrain drivetrain, double meters) {\n        this.drivetrain = drivetrain;\n        this.distance = meters;\n        addRequirements(drivetrain);\n    }\n    \n    @Override\n    public void initialize() {\n        startingPose = drivetrain.getPose();\n    }\n    \n    @Override\n    public void execute() {\n        drivetrain.drive(1.0, 0, 0);  // Drive forward at full speed\n    }\n    \n    @Override\n    public boolean isFinished() {\n        double traveled = startingPose.getTranslation().getDistance(\n            drivetrain.getPose().getTranslation()\n        );\n        return traveled >= distance;\n    }\n    \n    @Override\n    public void end(boolean interrupted) {\n        drivetrain.drive(0, 0, 0);  // Stop\n    }\n}\n\n// Command to turn 90 degrees\npublic class Turn90Degrees extends Command {\n    private final Drivetrain drivetrain;\n    private Rotation2d startingHeading;\n    \n    public Turn90Degrees(Drivetrain drivetrain) {\n        this.drivetrain = drivetrain;\n        addRequirements(drivetrain);\n    }\n    \n    @Override\n    public void initialize() {\n        startingHeading = drivetrain.getPose().getRotation();\n    }\n    \n    @Override\n    public void execute() {\n        drivetrain.drive(0, 0, Math.PI / 4);  // Turn at 45°/second\n    }\n    \n    @Override\n    public boolean isFinished() {\n        Rotation2d currentHeading = drivetrain.getPose().getRotation();\n        double degreesTurned = startingHeading.minus(currentHeading).getDegrees();\n        return Math.abs(degreesTurned) >= 90;\n    }\n    \n    @Override\n    public void end(boolean interrupted) {\n        drivetrain.drive(0, 0, 0);  // Stop\n    }\n}\n\n// Complete square auto\npublic Command squareAuto() {\n    return Commands.sequence(\n        new DriveDistance(drivetrain, 2.0),\n        new Turn90Degrees(drivetrain),\n        new DriveDistance(drivetrain, 2.0),\n        new Turn90Degrees(drivetrain),\n        new DriveDistance(drivetrain, 2.0),\n        new Turn90Degrees(drivetrain),\n        new DriveDistance(drivetrain, 2.0),\n        new Turn90Degrees(drivetrain)\n    );\n}\n"}]},{"type":"horizontalRule"},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"Challenge 2: precise Position Control"}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"🎯 Goal"}]},{"type":"paragraph","content":[{"type":"text","text":"Make the robot drive to a specific position (3m, 2m) on the field and stop within 10cm."}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"📋 Requirements"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Start anywhere on field."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Drive to position (3, 2)"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Stop within 10cm of target."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Face in the direction of movement."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Work in simulation."}]}]}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"💡 Hints"}]},{"type":"paragraph","content":[{"type":"text","text":"Hint 1: Use PID Controller"}]},{"type":"paragraph","content":[{"type":"text","text":"A PID controller can help you reach a precise position. ARESLib has built-in path following!"}]},{"type":"paragraph","content":[{"type":"text","text":"Hint 2: Holonomic Drive"}]},{"type":"paragraph","content":[{"type":"text","text":"Swerve drive can move in any direction while facing any direction. Use this to your advantage!"}]},{"type":"paragraph","content":[{"type":"text","text":"Hint 3: PathPlanner"}]},{"type":"paragraph","content":[{"type":"text","text":"PathPlanner can create paths to specific positions. You can load a path that goes to (3, 2)."}]},{"type":"codeBlock","attrs":{"language":"java"},"content":[{"type":"text","text":"PathPlannerPath path = PathPlanner.loadPath(\"ToTarget\", 3.0, 4.0);\n"}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"✅ Solution"}]},{"type":"paragraph","content":[{"type":"text","text":"👁️ Reveal Solution"}]},{"type":"codeBlock","attrs":{"language":"java"},"content":[{"type":"text","text":"public class DriveToPosition extends Command {\n    private final Drivetrain drivetrain;\n    private final Pose2d targetPose;\n    private final PIDController xController;\n    private final PIDController yController;\n    private final PIDController thetaController;\n    \n    public DriveToPosition(Drivetrain drivetrain, double x, double y, double headingDegrees) {\n        this.drivetrain = drivetrain;\n        this.targetPose = new Pose2d(x, y, Rotation2d.fromDegrees(headingDegrees));\n        \n        // Tune these for your robot!\n        xController = new PIDController(2.0, 0, 0);\n        yController = new PIDController(2.0, 0, 0);\n        thetaController = new PIDController(3.0, 0, 0);\n        thetaController.enableContinuousInput(-Math.PI, Math.PI);\n        \n        addRequirements(drivetrain);\n    }\n    \n    @Override\n    public void execute() {\n        Pose2d currentPose = drivetrain.getPose();\n        \n        // Calculate velocities to reach target\n        double xVelocity = xController.calculate(currentPose.getX(), targetPose.getX());\n        double yVelocity = yController.calculate(currentPose.getY(), targetPose.getY());\n        double thetaVelocity = thetaController.calculate(\n            currentPose.getRotation().getRadians(),\n            targetPose.getRotation().getRadians()\n        );\n        \n        // Drive robot\n        drivetrain.driveRobotRelative(\n            new ChassisSpeeds(xVelocity, yVelocity, thetaVelocity)\n        );\n    }\n    \n    @Override\n    public boolean isFinished() {\n        Pose2d currentPose = drivetrain.getPose();\n        double distance = currentPose.getTranslation().getDistance(\n            targetPose.getTranslation()\n        );\n        double headingError = Math.abs(currentPose.getRotation().minus(\n            targetPose.getRotation()\n        ).getDegrees());\n        \n        // Stop when close enough\n        return distance < 0.1 && headingError < 5.0;\n    }\n    \n    @Override\n    public void end(boolean interrupted) {\n        drivetrain.drive(0, 0, 0);  // Stop\n    }\n}\n\n// Use the command\npublic Command driveToTarget() {\n    return new DriveToPosition(drivetrain, 3.0, 2.0, 0.0);\n}\n"}]},{"type":"horizontalRule"},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"Challenge 3: Pick Up and Score Game Piece"}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"🎯 Goal"}]},{"type":"paragraph","content":[{"type":"text","text":"Create an auto routine that:"}]},{"type":"orderedList","attrs":{"start":1,"type":null},"content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Drives to a game piece."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Picks it up with intake."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Drives to scoring position."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Scores the piece."}]}]}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"📋 Requirements"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Use at least 2 subsystems (drivetrain + intake/shooter)"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Sequence commands properly."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Handle timing for pickup and scoring."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Work in simulation."}]}]}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"💡 Hints"}]},{"type":"paragraph","content":[{"type":"text","text":"Hint 1: Use Commands.sequence()"}]},{"type":"paragraph","content":[{"type":"text","text":"Sequence commands run one after another:"}]},{"type":"codeBlock","attrs":{"language":"java"},"content":[{"type":"text","text":"Commands.sequence(\n    driveToIntake,\n    intakePiece,\n    driveToScore,\n    scorePiece\n);\n"}]},{"type":"paragraph","content":[{"type":"text","text":"Hint 2: Use Commands.deadline() for timing"}]},{"type":"paragraph","content":[{"type":"text","marks":[{"type":"code"}],"text":"Commands.deadline()"},{"type":"text","text":" runs a command but ends after a timeout:"}]},{"type":"codeBlock","attrs":{"language":"java"},"content":[{"type":"text","text":"Commands.deadline(\n    Commands.waitSeconds(2.0),  // Timeout\n    new IntakeCommand(intake)   // Command that runs\n);\n"}]},{"type":"paragraph","content":[{"type":"text","text":"Hint 3: Create Intake and Shooter commands"}]},{"type":"paragraph","content":[{"type":"text","text":"You need commands for:"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","marks":[{"type":"code"}],"text":"IntakeCommand"},{"type":"text","text":" - runs intake until piece detected."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","marks":[{"type":"code"}],"text":"ScoreCommand"},{"type":"text","text":" - runs shooter until piece scored."}]}]}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"✅ Solution"}]},{"type":"paragraph","content":[{"type":"text","text":"👁️ Reveal Solution"}]},{"type":"codeBlock","attrs":{"language":"java"},"content":[{"type":"text","text":"// Intake command - runs until has piece\npublic class IntakeCommand extends Command {\n    private final Intake intake;\n    \n    public IntakeCommand(Intake intake) {\n        this.intake = intake;\n        addRequirements(intake);\n    }\n    \n    @Override\n    public void initialize() {\n        intake.intake();  // Start intake motor\n    }\n    \n    @Override\n    public void execute() {\n        // Keep running\n    }\n    \n    @Override\n    public boolean isFinished() {\n        return intake.hasPiece();  // Stop when we have a piece\n    }\n    \n    @Override\n    public void end(boolean interrupted) {\n        intake.stop();  // Stop intake motor\n    }\n}\n\n// Shooter command - runs for specific time\npublic class ScoreCommand extends Command {\n    private final Shooter shooter;\n    private double startTime;\n    \n    public ScoreCommand(Shooter shooter) {\n        this.shooter = shooter;\n        addRequirements(shooter);\n    }\n    \n    @Override\n    public void initialize() {\n        startTime = Timer.getFPGATimestamp();\n        shooter.shoot();  // Start shooter\n    }\n    \n    @Override\n    public void execute() {\n        // Keep running\n    }\n    \n    @Override\n    public boolean isFinished() {\n        // Run for 2 seconds\n        return Timer.getFPGATimestamp() - startTime > 2.0;\n    }\n    \n    @Override\n    public void end(boolean interrupted) {\n        shooter.stop();  // Stop shooter\n    }\n}\n\n// Complete auto\npublic Command pickupAndScore() {\n    return Commands.sequence(\n        // Drive to piece (using PathPlanner)\n        AutoBuilder.followPath(PathPlanner.loadPath(\"ToIntake\", 3.0, 4.0)),\n        \n        // Intake the piece (timeout at 3 seconds in case no piece)\n        Commands.deadline(\n            Commands.waitSeconds(3.0),\n            new IntakeCommand(intake)\n        ),\n        \n        // Drive to scoring position\n        AutoBuilder.followPath(PathPlanner.loadPath(\"ToScore\", 3.0, 4.0)),\n        \n        // Score the piece\n        new ScoreCommand(shooter)\n    );\n}\n"}]},{"type":"horizontalRule"},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"Challenge 4: Balance on Charging Station"}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"🎯 Goal"}]},{"type":"paragraph","content":[{"type":"text","text":"Make the robot automatically balance on the charging station (or any inclined surface)."}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"📋 Requirements"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Detect when robot is on incline."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Adjust position to find balance point."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Stay balanced once level."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Work on real charging station or simulation."}]}]}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"💡 Hints"}]},{"type":"paragraph","content":[{"type":"text","text":"Hint 1: Use Gyroscope"}]},{"type":"paragraph","content":[{"type":"text","text":"The gyroscope tells you the robot''''s pitch (front/back tilt). Use this to detect the charging station."}]},{"type":"codeBlock","attrs":{"language":"java"},"content":[{"type":"text","text":"double pitch = drivetrain.getPitch();  // In radians\n"}]},{"type":"paragraph","content":[{"type":"text","text":"Hint 2: PID Control"}]},{"type":"paragraph","content":[{"type":"text","text":"Use a PID controller to drive based on pitch angle:"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Pitch > 0: Drive forward."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Pitch < 0: Drive backward."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Pitch ≈ 0: Stop (balanced!)"}]}]}]},{"type":"paragraph","content":[{"type":"text","text":"Hint 3: Deadband"}]},{"type":"paragraph","content":[{"type":"text","text":"Add a small deadband so tiny fluctuations don''''t cause movement:"}]},{"type":"codeBlock","attrs":{"language":"java"},"content":[{"type":"text","text":"if (Math.abs(pitch) < 0.05) {\n    // Close enough to balanced, stop\n}\n"}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"✅ Solution"}]},{"type":"paragraph","content":[{"type":"text","text":"👁️ Reveal Solution"}]},{"type":"codeBlock","attrs":{"language":"java"},"content":[{"type":"text","text":"public class BalanceCommand extends Command {\n    private final Drivetrain drivetrain;\n    private final PIDController controller;\n    \n    public BalanceCommand(Drivetrain drivetrain) {\n        this.drivetrain = drivetrain;\n        \n        // Tune these for your robot!\n        // P: How aggressively to correct imbalance\n        // D: Dampen oscillation\n        controller = new PIDController(2.0, 0.0, 0.5);\n        \n        addRequirements(drivetrain);\n    }\n    \n    @Override\n    public void execute() {\n        double pitch = drivetrain.getPitch();  // Get robot tilt\n        \n        // Calculate drive speed based on pitch\n        double output = controller.calculate(pitch, 0.0);  // Target = 0 (level)\n        \n        // Deadband - if we''''re close enough, stop\n        if (Math.abs(pitch) < 0.05) {  // ~3 degrees\n            drivetrain.drive(0, 0, 0);\n        } else {\n            drivetrain.drive(output, 0, 0);  // Drive forward/backward\n        }\n    }\n    \n    @Override\n    public boolean isFinished() {\n        // Never finish - driver will cancel when done\n        return false;\n    }\n}\n\n// Use it\npublic Command autoBalance() {\n    return Commands.sequence(\n        // Drive onto charging station\n        new DriveDistance(drivetrain, 2.0),\n        // Balance\n        new BalanceCommand(drivetrain)\n    );\n}\n"}]},{"type":"horizontalRule"},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"Challenge 5: Vision-Assisted Scoring"}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"🎯 Goal"}]},{"type":"paragraph","content":[{"type":"text","text":"Use vision to automatically aim and score at a target."}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"📋 Requirements"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Detect target with camera."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Aim robot at target."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Drive to correct distance."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Score when aligned."}]}]}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"💡 Hints"}]},{"type":"paragraph","content":[{"type":"text","text":"Hint 1: Vision gives you target position"}]},{"type":"paragraph","content":[{"type":"text","text":"Your vision system should provide:"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Target yaw (left/right angle)"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Target distance (how far away)"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Target pitch (up/down angle)"}]}]}]},{"type":"paragraph","content":[{"type":"text","text":"Hint 2: PID for aiming"}]},{"type":"paragraph","content":[{"type":"text","text":"Use PID to control rotation based on target yaw:"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Yaw > 0: Turn right."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Yaw < 0: Turn left."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Yaw ≈ 0: Aimed!"}]}]}]},{"type":"paragraph","content":[{"type":"text","text":"Hint 3: Distance control"}]},{"type":"paragraph","content":[{"type":"text","text":"Use another PID for distance control:"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Too far: Drive forward."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Too close: Drive backward."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Correct distance: Stop and score."}]}]}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"✅ Solution"}]},{"type":"paragraph","content":[{"type":"text","text":"👁️ Reveal Solution"}]},{"type":"codeBlock","attrs":{"language":"java"},"content":[{"type":"text","text":"public class VisionAimCommand extends Command {\n    private final Drivetrain drivetrain;\n    private final VisionIO vision;\n    private final Shooter shooter;\n    \n    private final PIDController turnController;\n    private final PIDController distanceController;\n    \n    public VisionAimCommand(Drivetrain drivetrain, VisionIO vision, Shooter shooter) {\n        this.drivetrain = drivetrain;\n        this.vision = vision;\n        this.shooter = shooter;\n        \n        turnController = new PIDController(3.0, 0, 0.5);\n        distanceController = new PIDController(2.0, 0, 0.3);\n        \n        addRequirements(drivetrain);\n    }\n    \n    @Override\n    public void execute() {\n        // Get target data from vision\n        Optional<div data-component=\"VisionData\"></div> target = vision.getTarget();\n        \n        if (target.isEmpty()) {\n            // No target visible, stop\n            drivetrain.drive(0, 0, 0);\n            return;\n        }\n        \n        VisionData data = target.get();\n        \n        // Calculate outputs\n        double turnOutput = turnController.calculate(data.getYaw(), 0.0);\n        double driveOutput = distanceController.calculate(\n            data.getDistance(),\n            2.0  // Target distance: 2 meters\n        );\n        \n        // Drive robot\n        drivetrain.drive(driveOutput, 0, turnOutput);\n    }\n    \n    @Override\n    public boolean isFinished() {\n        // Check if aligned and at correct distance\n        Optional<div data-component=\"VisionData\"></div> target = vision.getTarget();\n        if (target.isEmpty()) return false;\n        \n        VisionData data = target.get();\n        boolean aligned = Math.abs(data.getYaw()) < 0.05;  // ~3 degrees\n        boolean correctDistance = Math.abs(data.getDistance() - 2.0) < 0.1;  // 10cm\n        \n        return aligned && correctDistance;\n    }\n    \n    @Override\n    public void end(boolean interrupted) {\n        drivetrain.drive(0, 0, 0);\n        \n        // If we finished (not interrupted), score!\n        if (!interrupted) {\n            shooter.score();\n        }\n    }\n}\n"}]},{"type":"horizontalRule"},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"Keep Practicing!"}]},{"type":"paragraph","content":[{"type":"text","text":"These challenges are just the beginning. Keep creating your own challenges:"}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"More Challenge Ideas:"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","marks":[{"type":"bold"}],"text":"Curve Follower"},{"type":"text","text":": Follow a curved path precisely."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","marks":[{"type":"bold"}],"text":"Obstacle Avoidance"},{"type":"text","text":": Navigate around obstacles."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","marks":[{"type":"bold"}],"text":"Multi-Piece Auto"},{"type":"text","text":": Pick up and score multiple pieces."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","marks":[{"type":"bold"}],"text":"Defensive Auto"},{"type":"text","text":": Block opponent while scoring."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","marks":[{"type":"bold"}],"text":"Emergency Recovery"},{"type":"text","text":": Recover from tipover or collision."}]}]}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Tips for Creating Challenges:"}]},{"type":"orderedList","attrs":{"start":1,"type":null},"content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","marks":[{"type":"bold"}],"text":"Start with what you know"},{"type":"text","text":" - Modify existing examples."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","marks":[{"type":"bold"}],"text":"Break it down"},{"type":"text","text":" - Divide complex tasks into simple ones."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","marks":[{"type":"bold"}],"text":"Test often"},{"type":"text","text":" - Verify each piece works."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","marks":[{"type":"bold"}],"text":"Learn from mistakes"},{"type":"text","text":" - Debugging is learning!"}]}]}]},{"type":"horizontalRule"},{"type":"paragraph","content":[{"type":"text","marks":[{"type":"bold"}],"text":"Ready for more?"},{"type":"text","text":" Check out "},{"type":"text","marks":[{"type":"link","attrs":{"href":"/interactive/exercises/advanced","target":"_blank","rel":"noopener noreferrer nofollow","class":null,"title":null}}],"text":"Advanced Challenges"},{"type":"text","text":" when you master these!"}]},{"type":"paragraph","content":[{"type":"text","marks":[{"type":"bold"}],"text":"Stuck on a challenge?"},{"type":"text","text":" Ask for help on "},{"type":"text","marks":[{"type":"link","attrs":{"href":"https://github.com/ARESProgramming/ARESLib/discussions","target":"_blank","rel":"noopener noreferrer nofollow","class":null,"title":null}}],"text":"Discussions"},{"type":"text","text":" - explain what you''''ve tried and what''''s not working."}]}]}', 20, 'Interactive Lessons');
INSERT INTO docs (slug, title, content, sort_order, category) VALUES ('interactive-java-basics-quiz', 'Untitled', '{"type":"doc","content":[{"type":"horizontalRule"},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"title: \"Java Basics Quiz\" description: \"Test your Java programming knowledge with this interactive quiz.\" sidebar: order: 1"}]},{"type":"paragraph","content":[{"type":"text","text":"Test your Java skills! This quiz checks if you''''re ready for FTC programming."}]},{"type":"paragraph","content":[{"type":"text","marks":[{"type":"bold"}],"text":"Each question shows the answer immediately"},{"type":"text","text":" so you can learn as you go."}]},{"type":"horizontalRule"},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"Question 1: Variables"}]},{"type":"paragraph","content":[{"type":"text","marks":[{"type":"bold"}],"text":"What does this code print?"}]},{"type":"codeBlock","attrs":{"language":"java"},"content":[{"type":"text","text":"int score = 10;\nscore = score + 5;\nSystem.out.println(score);\n"}]},{"type":"paragraph","content":[{"type":"text","text":"Show Answer"}]},{"type":"paragraph","content":[{"type":"text","marks":[{"type":"bold"}],"text":"Answer: 15"}]},{"type":"paragraph","content":[{"type":"text","marks":[{"type":"bold"}],"text":"Why?"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"First line: "},{"type":"text","marks":[{"type":"code"}],"text":"score"},{"type":"text","text":" is set to 10."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Second line: "},{"type":"text","marks":[{"type":"code"}],"text":"score + 5"},{"type":"text","text":" = 15, then "},{"type":"text","marks":[{"type":"code"}],"text":"score = 15"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Third line: Prints 15."}]}]}]},{"type":"paragraph","content":[{"type":"text","marks":[{"type":"bold"}],"text":"Think of it like"},{"type":"text","text":":"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"You have a box labeled \"score\"."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Put 10 in the box."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Add 5 more to the box."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Now the box has 15."}]}]}]},{"type":"horizontalRule"},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"Question 2: Strings"}]},{"type":"paragraph","content":[{"type":"text","marks":[{"type":"bold"}],"text":"What does this code print?"}]},{"type":"codeBlock","attrs":{"language":"java"},"content":[{"type":"text","text":"String name = \"FTC\";\nString greeting = \"Hello \" + name;\nSystem.out.println(greeting);\n"}]},{"type":"paragraph","content":[{"type":"text","text":"Show Answer"}]},{"type":"paragraph","content":[{"type":"text","marks":[{"type":"bold"}],"text":"Answer: Hello FTC"}]},{"type":"paragraph","content":[{"type":"text","marks":[{"type":"bold"}],"text":"Why?"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","marks":[{"type":"code"}],"text":"+"},{"type":"text","text":" joins strings together (called concatenation)"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","marks":[{"type":"code"}],"text":"\"Hello \" + \"FTC\""},{"type":"text","text":" = "},{"type":"text","marks":[{"type":"code"}],"text":"\"Hello FTC\""}]}]}]},{"type":"paragraph","content":[{"type":"text","marks":[{"type":"bold"}],"text":"Think of it like"},{"type":"text","text":":"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Glue two pieces of paper together."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"One says \"Hello \", the other says \"FTC\"."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"After gluing: \"Hello FTC\"."}]}]}]},{"type":"horizontalRule"},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"Question 3: If Statements"}]},{"type":"paragraph","content":[{"type":"text","marks":[{"type":"bold"}],"text":"What does this code print?"}]},{"type":"codeBlock","attrs":{"language":"java"},"content":[{"type":"text","text":"int speed = 7;\nif (speed > 5) {\n    System.out.println(\"Fast!\");\n} else {\n    System.out.println(\"Slow\");\n}\n"}]},{"type":"paragraph","content":[{"type":"text","text":"Show Answer"}]},{"type":"paragraph","content":[{"type":"text","marks":[{"type":"bold"}],"text":"Answer: Fast!"}]},{"type":"paragraph","content":[{"type":"text","marks":[{"type":"bold"}],"text":"Why?"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","marks":[{"type":"code"}],"text":"speed"},{"type":"text","text":" is 7"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","marks":[{"type":"code"}],"text":"7 > 5"},{"type":"text","text":" is true."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Run the code inside "},{"type":"text","marks":[{"type":"code"}],"text":"if"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Skip the code inside "},{"type":"text","marks":[{"type":"code"}],"text":"else"}]}]}]},{"type":"paragraph","content":[{"type":"text","marks":[{"type":"bold"}],"text":"Think of it like"},{"type":"text","text":":"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"\"Is the speed greater than 5?\"."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Yes! Print \"Fast!\"."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"No need to check the \"else\" part."}]}]}]},{"type":"horizontalRule"},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"Question 4: If-Else If"}]},{"type":"paragraph","content":[{"type":"text","marks":[{"type":"bold"}],"text":"What does this code print?"}]},{"type":"codeBlock","attrs":{"language":"java"},"content":[{"type":"text","text":"int score = 85;\nif (score >= 90) {\n    System.out.println(\"A\");\n} else if (score >= 80) {\n    System.out.println(\"B\");\n} else {\n    System.out.println(\"C\");\n}\n"}]},{"type":"paragraph","content":[{"type":"text","text":"Show Answer"}]},{"type":"paragraph","content":[{"type":"text","marks":[{"type":"bold"}],"text":"Answer: B"}]},{"type":"paragraph","content":[{"type":"text","marks":[{"type":"bold"}],"text":"Why?"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","marks":[{"type":"code"}],"text":"score"},{"type":"text","text":" is 85"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","marks":[{"type":"code"}],"text":"85 >= 90"},{"type":"text","text":"? No, skip first block."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","marks":[{"type":"code"}],"text":"85 >= 80"},{"type":"text","text":"? Yes! Print \"B\"."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Skip the "},{"type":"text","marks":[{"type":"code"}],"text":"else"},{"type":"text","text":" block."}]}]}]},{"type":"paragraph","content":[{"type":"text","marks":[{"type":"bold"}],"text":"Think of it like"},{"type":"text","text":":"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Check conditions in order."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Stop at the first one that''''s true."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Don''''t check the rest."}]}]}]},{"type":"horizontalRule"},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"Question 5: Loops"}]},{"type":"paragraph","content":[{"type":"text","marks":[{"type":"bold"}],"text":"How many times does this print?"}]},{"type":"codeBlock","attrs":{"language":"java"},"content":[{"type":"text","text":"for (int i = 0; i < 3; i++) {\n    System.out.println(\"Hello\");\n}\n"}]},{"type":"paragraph","content":[{"type":"text","text":"Show Answer"}]},{"type":"paragraph","content":[{"type":"text","marks":[{"type":"bold"}],"text":"Answer: 3 times"}]},{"type":"paragraph","content":[{"type":"text","marks":[{"type":"bold"}],"text":"Why?"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","marks":[{"type":"code"}],"text":"i = 0"},{"type":"text","text":": Print (i is 0, 0 < 3)"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","marks":[{"type":"code"}],"text":"i = 1"},{"type":"text","text":": Print (i is 1, 1 < 3)"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","marks":[{"type":"code"}],"text":"i = 2"},{"type":"text","text":": Print (i is 2, 2 < 3)"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","marks":[{"type":"code"}],"text":"i = 3"},{"type":"text","text":": Stop (i is 3, 3 < 3 is false)"}]}]}]},{"type":"paragraph","content":[{"type":"text","marks":[{"type":"bold"}],"text":"Think of it like"},{"type":"text","text":":"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Count: 0, 1, 2."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"That''''s 3 numbers."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Print 3 times"}]}]}]},{"type":"horizo