\n"}]},{"type":"paragraph","content":[{"type":"text","marks":[{"type":"bold"}],"text":"Control Hub CAN ports"},{"type":"text","text":":"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","marks":[{"type":"code"}],"text":"CAN 0"},{"type":"text","text":": Primary CAN bus."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","marks":[{"type":"code"}],"text":"CAN 1"},{"type":"text","text":": Secondary CAN bus (if using CANivore)"}]}]}]},{"type":"paragraph","content":[{"type":"text","marks":[{"type":"bold"}],"text":"Make sure devices are on correct bus!"}]},{"type":"horizontalRule"},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Problem 2: CAN Bus Utilization Too High"}]},{"type":"paragraph","content":[{"type":"text","marks":[{"type":"bold"}],"text":"Symptoms"},{"type":"text","text":":"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Phoenix Tuner shows >80% utilization."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Robot behaves randomly."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Some devices work, others don''''t."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Performance issues."}]}]}]},{"type":"paragraph","content":[{"type":"text","marks":[{"type":"bold"}],"text":"Causes"},{"type":"text","text":":"}]},{"type":"paragraph","content":[{"type":"text","marks":[{"type":"bold"}],"text":"1. Update Rates Too High"}]},{"type":"codeBlock","attrs":{"language":null},"content":[{"type":"text","text":"Fix: Reduce update rates for non-critical signals\n"}]},{"type":"paragraph","content":[{"type":"text","marks":[{"type":"bold"}],"text":"What to update fast (100Hz)"},{"type":"text","text":":"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"para