content":[{"type":"paragraph","content":[{"type":"text","text":"Mechanism motor velocities."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Important sensor data."}]}]}]},{"type":"paragraph","content":[{"type":"text","marks":[{"type":"bold"}],"text":"10Hz (slow)"},{"type":"text","text":":"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Motor temperatures."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Battery voltage/current."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Non-critical telemetry."}]}]}]},{"type":"paragraph","content":[{"type":"text","marks":[{"type":"bold"}],"text":"4Hz (very slow)"},{"type":"text","text":":"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Status signals."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Fault indicators."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Diagnostic data."}]}]}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Physical Setup Tips"}]},{"type":"paragraph","content":[{"type":"text","marks":[{"type":"bold"}],"text":"Good Practices"},{"type":"text","text":":"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Keep CAN cables as short as possible."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Use right-angle connectors in tight spaces."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Add strain relief to prevent pull-out."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Label both ends of each cable."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Test continuity before installing."}]}]}]},{"type":"paragraph","content":[{"type":"text","marks":[{"type":"bold"}],"text":"Bad Practices to Avoid"},{"type":"text","text":":"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Don''''t splice CAN cables."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Don''''t make cables longer than 6 feet."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Don''''t run CAN next to motor power."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Don''''t leave slack cables loose."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Don''''t use different colored cables (confusing)"}]}]}]},{"type":"horizontalRule"},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"Monitoring CAN Health"}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"During Competition"}]},{"type":"codeBlock","attrs":{"language":"java"},"content":[{"type":"text","text":"// Add to your robot periodic()\npublic void robotPeriodic() {\n    // Check CAN bus health\n    double utilization = PDP.getCANBusUtilization();\n    SmartDashboard.putNumber(\"CAN Utilization\", utilization);\n    \n    if (utilization > 0.8) {\n        DriverStation.reportWarning(\"CAN utilization high: \" + utilization, false);\n    }\n}\n"}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Logging CAN Errors"}]},{"type":"codeBlock","attrs":{"language":"java"},"content":[{"type":"text","text":"// Log CAN errors for analysis\n@Override\npublic void periodic() {\n    StatusCode status = motor.getFault_DeviceID();\n    if (status != StatusCode.OK) {\n        System.out.println(\"Motor fault: \" + status);\n        // Log to file or send telemetry\n    }\n}\n"}]},{"type":"horizontalRule"},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"Common CAN Device Counts"}]},{"type":"paragraph","content":[{"type":"text","marks":[{"type":"bold"}],"text":"Typical robot configurations"},{"type":"text","text":":"}]},{"type":"paragraph","content":[{"type":"text","marks":[{"type":"bold"}],"text":"Basic Kitbot"},{"type":"text","text":":"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"4x Spark MAX/Talon SRX (drivetrain)"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","marks":[{"type":"bold"}],"text":"Total"},{"type":"text","text":": 4 devices (easy, one bus fine)"}]}]}]},{"type":"paragraph","content":[{"type":"text","marks":[{"type":"bold"}],"text":"Competitive Drivetrain"},{"type":"text","text":":"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"4x Talon FX (drive motors)"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"4x CANcoder (wheel encoders)"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"1x Pigeon2 (gyro)"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","marks":[{"type":"bold"}],"text":"Total"},{"type":"text","text":": 9 devices (still okay, one bus)"}]}]}]},{"type":"paragraph","content":[{"type":"text","marks":[{"type":"bold"}],"text":"Full Competition Robot"},{"type":"text","text":":"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"4x Talon FX (drivetrain)"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"4x CANcoder (drivetrain)"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"1x Pigeon2 (gyro)"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"2x Talon FX (shooter)"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"2x Talon FX (intake)"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"1x CANcoder (intake sensor)"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","marks":[{"type":"bold"}],"text":"Total"},{"type":"text","text":": 14 devices (use CANivore)"}]}]}]},{"type":"horizontalRule"},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"When to Get Help"}]},{"type":"paragraph","content":[{"type":"text","text":"If you''''ve tried everything and CAN still doesn''''t work:"}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Good Help Request:"}]},{"type":"codeBlock","attrs":{"language":null},"content":[{"type":"text","text":"\"Having CAN bus communication issues.\n\nRobot setup:\n- 4x Talon FX for drivetrain (IDs 1-4)\n- 4x CANcoder for wheel sensors (IDs 5-8)\n- 1x Pigeon2 gyro (ID 9)\n- Connected to Control Hub CAN 0\n- 120Ω terminator at end\n\nSymptoms:\n- CAN utilization spikes to 95% when driving\n- Random \"CAN Receive Timeout\" errors\n- Devices 5-8 sometimes don''''t appear in Phoenix Tuner\n- Drivetrain motors work, encoders don''''t always\n\nWhat I''''ve tried:\n- Reduced all non-critical update rates to 4Hz\n- Checked all CAN connections (all secure)\n- Verified device IDs match code\n- Updated firmware on all devices\n- Tested with only drivetrain (works fine)\n- Tested with encoders only (fails with drivetrain)\n\nPhoenix Tuner shows:\n- Utilization: 95% when driving, 20% when idle\n- All devices show green when they appear\n- Random device dropouts during motion\n\nWhat should I check next?\"\n"}]},{"type":"horizontalRule"},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"Related Guides"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","marks":[{"type":"link","attrs":{"href":"/framework-structure/io-layer","target":"_blank","rel":"noopener noreferrer nofollow","class":null,"title":null}}],"text":"Motor Configuration"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","marks":[{"type":"link","attrs":{"href":"/operations/network-configuration","target":"_blank","rel":"noopener noreferrer nofollow","class":null,"title":null}}],"text":"CAN Bus Best Practices"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","marks":[{"type":"link","attrs":{"href":"/advanced/performance","target":"_blank","rel":"noopener noreferrer nofollow","class":null,"title":null}}],"text":"Performance Optimization"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","marks":[{"type":"link","attrs":{"href":"/operations/checklist","target":"_blank","rel":"noopener noreferrer nofollow","class":null,"title":null}}],"text":"Electrical Wiring"}]}]}]},{"type":"horizontalRule"},{"type":"paragraph","content":[{"type":"text","marks":[{"type":"bold"}],"text":"Remember"},{"type":"text","text":": CAN bus is the nervous system of your robot. Keep it healthy and your robot will work reliably!"}]},{"type":"paragraph","content":[{"type":"text","marks":[{"type":"bold"}],"text":"Still having CAN issues?"},{"type":"text","text":" "},{"type":"text","marks":[{"type":"link","attrs":{"href":"https://github.com/ARESProgramming/ARESLib/discussions","target":"_blank","rel":"noopener noreferrer nofollow","class":null,"title":null}}],"text":"Ask the community"},{"type":"text","text":" - describe your setup and symptoms!"}]}]}', 50, 'Operations & Troubleshooting');
