INSERT INTO docs (slug, title, content, sort_order, category) VALUES ('troubleshooting-robot-wont-move', 'Untitled', '{"type":"doc","content":[{"type":"horizontalRule"},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"title: \"Robot Won''''t Move - Troubleshooting Guide\" description: \"Step-by-step checklist to diagnose and fix why your robot won''''t move.\" sidebar: order: 1"}]},{"type":"paragraph","content":[{"type":"text","text":"Every technical hurdle is an opportunity for "},{"type":"text","marks":[{"type":"bold"}],"text":"Discovery"},{"type":"text","text":". If your robot isn''''t moving as expected, don''''t panic—this is where your team''''s "},{"type":"text","marks":[{"type":"bold"}],"text":"Innovation"},{"type":"text","text":" and "},{"type":"text","marks":[{"type":"bold"}],"text":"Teamwork"},{"type":"text","text":" shine. Follow this checklist to systematically diagnose the issue, turning a stressful moment into a "},{"type":"text","marks":[{"type":"bold"}],"text":"Fun"},{"type":"text","text":" learning experience and ensuring your robot makes its next high-"},{"type":"text","marks":[{"type":"bold"}],"text":"Impact"},{"type":"text","text":" appearance on the field."}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"Quick Check (30 seconds)"}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"1. Is Robot Code Running?"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Look at the Driver Station."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Is \"Robot Code\" showing "},{"type":"text","marks":[{"type":"bold"}],"text":"GREEN"},{"type":"text","text":"?"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"❌ "},{"type":"text","marks":[{"type":"bold"}],"text":"RED/YELLOW"},{"type":"text","text":": Code isn''''t running."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"✅ "},{"type":"text","marks":[{"type":"bold"}],"text":"GREEN"},{"type":"text","text":": Code is running, skip to Step 2."}]}]}]}]}]},{"type":"paragraph","content":[{"type":"text","marks":[{"type":"bold"}],"text":"If not green:"}]},{"type":"orderedList","attrs":{"start":1,"type":null},"content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Check for errors in RioLog."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Reboot the Control Hub."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Restart the Driver Station."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Redeploy code if needed."}]}]}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"2. Is Robot Enabled?"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Look at Driver Station mode."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Are you in "},{"type":"text","marks":[{"type":"bold"}],"text":"Teleop"},{"type":"text","text":", "},{"type":"text","marks":[{"type":"bold"}],"text":"Auto"},{"type":"text","text":", or "},{"type":"text","marks":[{"type":"bold"}],"text":"Test"},{"type":"text","text":" mode?"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Is the "},{"type":"text","marks":[{"type":"bold"}],"text":"ENABLE"},{"type":"text","text":" button pressed?"}]}]}]},{"type":"paragraph","content":[{"type":"text","marks":[{"type":"bold"}],"text":"If disabled:"}]},{"type":"orderedList","attrs":{"start":1,"type":null},"content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Click the mode you want (usually Teleop)"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Click the ENABLE button."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Robot should move now."}]}]}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"3. Is Controller Connected?"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Look at Driver Station USB tab."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Do you see your controller?"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Are the lights on the controller on?"}]}]}]},{"type":"paragraph","content":[{"type":"text","marks":[{"type":"bold"}],"text":"If not connected:"}]},{"type":"orderedList","attrs":{"start":1,"type":null},"content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Unplug and replug controller."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Try different USB port."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Replace controller batteries."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Try different controller."}]}]}]},{"type":"horizontalRule"},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"Detailed Diagnosis (5 minutes)"}]},{"type":"paragraph","content":[{"type":"text","text":"If quick check didn''''t fix it, work through these steps:"}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Step 1: Check Joystick Input (1 minute)"}]},{"type":"paragraph","content":[{"type":"text","marks":[{"type":"bold"}],"text":"Print joystick values to see if they''''re being read:"}]},{"type":"codeBlock","attrs":{"language":"java"},"content":[{"type":"text","text":"@Override\npublic void execute() {\n    double forward = -controller.getLeftY();\n    double strafe = controller.getLeftX();\n    double rotate = controller.getRightX();\n    \n    // Add this to debug\n    System.out.println(\"Joystick: F=\" + forward + \" S=\" + strafe + \" R=\" + rotate);\n    \n    drivetrain.drive(forward, strafe, rotate);\n}\n"}]},{"type":"paragraph","content":[{"type":"text","marks":[{"type":"bold"}],"text":"What to look for:"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"✅ "},{"type":"text","marks":[{"type":"bold"}],"text":"Values changing"},{"type":"text","text":": Joystick works, problem is elsewhere."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"❌ "},{"type":"text","marks":[{"type":"bold"}],"text":"Always zero"},{"type":"text","text":": Joystick not being read."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"❌ "},{"type":"text","marks":[{"type":"bold"}],"text":"No output"},{"type":"text","text":": Command isn''''t running."}]}]}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Step 2: Verify Command is Running (1 minute)"}]},{"type":"paragraph","content":[{"type":"text","marks":[{"type":"bold"}],"text":"Add debug print to see if command runs:"}]},{"type":"codeBlock","attrs":{"language":"java"},"content":[{"type":"text","text":"public DriveCommand(Drivetrain drivetrain, XboxController controller) {\n    this.drivetrain = drivetrain;\n    this.controller = controller;\n    addRequirements(drivetrain);\n    System.out.println(\"DriveCommand created!\");  // Add this\n}\n\n@Override\npublic void execute() {\n    System.out.println(\"DriveCommand executing!\");  // Add this\n    // ... rest of code\n}\n"}]},{"type":"paragraph","content":[{"type":"text","marks":[{"type":"bold"}],"text":"What to look for:"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"✅ "},{"type":"text","marks":[{"type":"bold"}],"text":"\"executing!\" prints every 20ms"},{"type":"text","text":": Command is running."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"❌ "},{"type":"text","marks":[{"type":"bold"}],"text":"Only \"created!\" once"},{"type":"text","text":": Command not scheduled."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"❌ "},{"type":"text","marks":[{"type":"bold"}],"text":"No output at all"},{"type":"text","text":": Command not being created."}]}]}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Step 3: Check Default Command (1 minute)"}]},{"type":"paragraph","content":[{"type":"text","marks":[{"type":"bold"}],"text":"Make sure drivetrain has a default command:"}]},{"type":"codeBlock","attrs":{"language":"java"},"content":[{"type":"text","text":"public RobotContainer() {\n    // In RobotContainer.java\n    drivetrain.setDefaultCommand(\n        new DriveCommand(drivetrain, driver)\n    );\n}\n"}]},{"type":"paragraph","content":[{"type":"text","marks":[{"type":"bold"}],"text":"Verify it''''s set:"}]},{"type":"orderedList","attrs":{"start":1,"type":null},"content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Add print to RobotContainer constructor."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Look for \"DriveCommand created!\" in RioLog."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Check that default command is actually set."}]}]}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Step 4: Check Subsystem (1 minute)"}]},{"type":"paragraph","content":[{"type":"text","marks":[{"type":"bold"}],"text":"Add debug to subsystem:"}]},{"type":"codeBlock","attrs":{"language":"java"},"content":[{"type":"text","text":"public void drive(double forward, double strafe, double rotate) {\n    System.out.print